import React from "react";
import classes from "./MainHeaderTab.module.css";

const MainHeaderTab = (props) => {
  const setTabHandler = () => {
    props.setTab(props.title);
  };

  console.log(props.selectedTab);

  return (
    <div className={classes["tab"]} onClick={setTabHandler}>
      {props.title}
    </div>
  );
};

export default React.memo(MainHeaderTab);
